param([string]$FixturePath='examples/r5-h4-feedback-fixtures/fixtures.json',[string]$ReportPath='state/checks/r5-h4-feedback-ledger-report.json')
$ErrorActionPreference='Stop';. (Join-Path $PSScriptRoot 'WindowsRuntimeHelper.ps1')
function Get-TermStatus($t){if(-not [string]::IsNullOrWhiteSpace([string]$t.blocked_reason)){return 'blocked'};if([int]$t.selected_candidate_assist_count -ge 2 -and [int]$t.selected_candidate_assist_count -gt [int]$t.rejected_candidate_assist_count){return 'preferred'};if([int]$t.rejected_candidate_assist_count -ge 2 -and [int]$t.rejected_candidate_assist_count -gt [int]$t.selected_candidate_assist_count){return 'deprioritized'};return 'exploration'}
try{$root=Split-Path -Parent $PSScriptRoot;$p=if([IO.Path]::IsPathRooted($FixturePath)){$FixturePath}else{Join-Path $root $FixturePath};$f=Get-Content $p -Raw -Encoding UTF8|ConvertFrom-Json;$rows=[Collections.Generic.List[object]]::new();foreach($c in @($f.cases)){$missing=@('run_count','signal_assist_count','candidate_assist_count','selected_candidate_assist_count','rejected_candidate_assist_count'|?{$null -eq $c.term.$_});$a=if($missing.Count){'invalid'}else{Get-TermStatus $c.term};$rows.Add([ordered]@{fixture_id=$c.fixture_id;expected=$c.expected;actual=$a;expectation_met=($a -eq $c.expected);missing=$missing})};$bad=@($rows|?{-not $_.expectation_met});$r=[ordered]@{schema_id='taoge://reports/r5/h4-feedback/v0.1';overall_result=$(if($bad.Count){'fail'}else{'pass'});case_count=$rows.Count;failure_count=$bad.Count;results=@($rows)};$o=if([IO.Path]::IsPathRooted($ReportPath)){$ReportPath}else{Join-Path $root $ReportPath};Write-TaogeUtf8NoBomJson -Path $o -Value $r -Depth 8;"R5_H4_FEEDBACK_LEDGER_CHECK=$($r.overall_result)";"CASE_COUNT=$($r.case_count)";if($bad.Count){exit 1}}catch{Write-Error $_;exit 3}
